  ('medical-tech-moex-09515', 'medical-tech', 'medical-tech-moex-105-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關實驗室監測INR之敘述，下列何者正確？', '["一般建議的治療目標為INR 2.0～3.0（平均2.5）", "須利用APTT", "在肝功能異常病人監測INR，作為出血風險評估最合適", "可以監測高劑量heparin之療效"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:37+00:00", "source_pdf_sha1": "d3e1f3fe4aca", "answer_pdf_sha1": "d85823e84ddc", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 50, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
