  ('medical-tech-moex-09517', 'medical-tech', 'medical-tech-moex-105-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '某檢驗結果如下：病人檢體PT為12秒、APTT為80秒、品管檢體PT為10秒、APTT為44秒、正常人混合血漿APTT為47秒、 APTT之參考區間為40～50秒。病人檢體與正常人血漿混合後立即測試 APTT 為47秒，則下列敘述何者正確？', '["檢體中無凝血因子抗體", "檢體可能有heparin污染", "須進一步執行37℃孵育（incubate）的混合試驗", "須進一步執行PT混合試驗"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:37+00:00", "source_pdf_sha1": "d3e1f3fe4aca", "answer_pdf_sha1": "d85823e84ddc", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 52, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
